/* Carga directa y temprana del panel de ciclos; no depende de main.js. */
(function(){
  var file=(location.pathname.split('/').pop()||'').toLowerCase();
  var cyclePages={
    'ciclo-anual-uni.html':1,'ciclo-semianual-uni.html':1,'ciclo-semestral-uni.html':1,
    'ciclo-repaso-uni.html':1,'ciclo-elite-uni.html':1,'ciclo-ien.html':1,
    'ciclo-proyecto-escolar.html':1,'ciclo-paralelo-cepre-uni.html':1,'ciclo-verano-uni.html':1
  };
  if(!cyclePages[file])return;
  if(document.querySelector('script[data-nostra-cycle-panel-direct="1"]'))return;
  var s=document.createElement('script');
  s.src='assets/js/nostra-cycle-sidebar-premium.js?v=2026-53';
  s.defer=true;
  s.setAttribute('data-nostra-cycle-panel-direct','1');
  (document.body||document.documentElement).appendChild(s);
})();
/* Carga directa de los CTA estratégicos de preinscripción del index. */
(function(){
  var file=(location.pathname.split('/').pop()||'index.html').toLowerCase();
  if(!(file==='index.html'||file===''||location.pathname==='/'))return;
  if(document.querySelector('script[data-nostra-index-pre="1"]'))return;
  var s=document.createElement('script');
  s.src='assets/js/nostra-index-preinscripcion-cta.js?v=2026-55';
  s.defer=true;
  s.setAttribute('data-nostra-index-pre','1');
  (document.body||document.documentElement).appendChild(s);
})();
